module top_module(input CLK_12M,input EVEN,input LOAD,input H,input [31:0] CR,output reg [3:0] GAD, GBD,output reg DOTA, DOTB);reg [31:0] obf_SR; 
  always @(negedge CLK_12M) 
  begin 
  if (LOAD) obf_SR <= CR; 
  else if (H) obf_SR <= {obf_SR[29:24], 2'b00, obf_SR[21:16], 2'b00, obf_SR[13:8], 2'b00, obf_SR[5:0], 2'b00}; 
  else obf_SR <= {2'b00, obf_SR[31:26], 2'b00, obf_SR[23:18], 2'b00, obf_SR[15:10], 2'b00, obf_SR[7:2]}; 
  end 
  always @* 
  begin 
  case ({EVEN, H}) 
  3: {GBD, GAD} <= {obf_SR[31], obf_SR[23], obf_SR[15], obf_SR[7], obf_SR[30], obf_SR[22], obf_SR[14], obf_SR[6]}; 
  2: {GBD, GAD} <= {obf_SR[24], obf_SR[16], obf_SR[8], obf_SR[0], obf_SR[25], obf_SR[17], obf_SR[9], obf_SR[1]}; 
  1: {GBD, GAD} <= {obf_SR[30], obf_SR[22], obf_SR[14], obf_SR[6], obf_SR[31], obf_SR[23], obf_SR[15], obf_SR[7]}; 
  0: {GBD, GAD} <= {obf_SR[25], obf_SR[17], obf_SR[9], obf_SR[1], obf_SR[24], obf_SR[16], obf_SR[8], obf_SR[0]}; 
  endcase 
  {DOTA, DOTB} <= {|GAD, |GBD}; 
  end 
 endmodule
